// Log Audit Trail
// Captures comprehensive audit information for governance tracking

const items = $input.all();
const auditLogs = [];

for (const item of items) {
  const timestamp = new Date().toISOString();
  const riskLevel = item.json.riskLevel || 'unknown';
  const approvalStatus = item.json.approvalStatus || item.json.status || 'pending';
  const notificationType = item.json.notificationType || item.json.notification_type || 'none';
  const governanceOutput = item.json;

  // Log to console for debugging
  console.log('=== AUDIT TRAIL ENTRY ===');
  console.log('Timestamp:', timestamp);
  console.log('Risk Level:', riskLevel);
  console.log('Approval Status:', approvalStatus);
  console.log('Notification Type:', notificationType);
  console.log('Full Governance Output:', JSON.stringify(governanceOutput, null, 2));
  console.log('========================');

  // Create structured audit log entry
  const auditEntry = {
    timestamp: timestamp,
    riskLevel: riskLevel,
    approvalStatus: approvalStatus,
    notificationType: notificationType,
    governanceOutput: governanceOutput,
    auditId: `audit-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`
  };

  auditLogs.push(auditEntry);
}

// Return structured audit logs
return auditLogs.map(log => ({ json: log }));
